import React, { useState } from "react";

export default function AddZapatilla() {
  const [nombre, setNombre] = useState("");
  const [marca, setMarca] = useState("");
  const [precio, setPrecio] = useState(0);
  const [cantidad, setCantidad] = useState(0);
  const [talle, setTalle] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    const nuevaZapatilla = {
      nombre,
      marca,
      precio,
      cantidad,
      talle,
    };

    try {
      const res = await fetch("http://localhost:8080/zapatillas", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(nuevaZapatilla),
      });

      if (res.ok) {
        alert("Zapatilla guardada con éxito");
        setNombre("");
        setMarca("");
        setPrecio(0);
        setCantidad(0);
        setTalle("");
      } else {
        alert("Error al guardar zapatilla");
      }
    } catch (error) {
      console.error("Error:", error);
      alert("Error de red al guardar zapatilla");
    }
  };

  return (
    <div className="p-4">
      <h2 className="text-2xl font-bold mb-4">Agregar nueva zapatilla</h2>
      <form onSubmit={handleSubmit} className="grid gap-4 max-w-md mx-auto">
        <input
          type="text"
          placeholder="Nombre"
          value={nombre}
          onChange={(e) => setNombre(e.target.value)}
          className="border p-2 rounded"
          required
        />
        <input
          type="text"
          placeholder="Marca"
          value={marca}
          onChange={(e) => setMarca(e.target.value)}
          className="border p-2 rounded"
          required
        />
        <h2 className="text-2xl font-bold mb-4">Agregar nueva zapatilla</h2>
        <input
          type="number"
          placeholder="Precio"
          value={precio}
          onChange={(e) => setPrecio(Number(e.target.value))}
          className="border p-2 rounded"
          required
        />
        <input
          type="number"
          placeholder="Cantidad"
          value={cantidad}
          onChange={(e) => setCantidad(Number(e.target.value))}
          className="border p-2 rounded"
          required
        />
        <input
          type="text"
          placeholder="Talle"
          value={talle}
          onChange={(e) => setTalle(e.target.value)}
          className="border p-2 rounded"
          required
        />
        <button
          type="submit"
          className="bg-orange-500 text-white py-2 px-4 rounded hover:bg-orange-600"
        >
          Guardar
        </button>
      </form>
    </div>
  );
}
